:root {
  --min-font-size: 1rem;
  --max-font-size: 1.25rem;
  --min-vw: 20rem; /* 320px */
  --max-vw: 80rem; /* 1280px */
  --fluid-ratio: calc((var(--max-font-size) - var(--min-font-size)) / (var(--max-vw) - var(--min-vw)));
}

body {
  font-family: 'Inter', sans-serif;
  font-size: clamp(var(--min-font-size), calc(var(--min-font-size) + (var(--fluid-ratio) * (100vw - var(--min-vw)))), var(--max-font-size));
  line-height: clamp(1.4, calc(1.4 + (var(--fluid-ratio) * (100vw - var(--min-vw)) * 0.5)), 1.6); /* Adjust line-height proportionally */
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

h1 {
  /* Example for heading, scales larger */
  --min-h1-size: 2rem;
  --max-h1-size: 4rem;
  font-size: clamp(var(--min-h1-size), calc(var(--min-h1-size) + ((var(--max-h1-size) - var(--min-h1-size)) / (var(--max-vw) - var(--min-vw))) * (100vw - var(--min-vw))), var(--max-h1-size));
  line-height: 1.1;
}
